"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ─── Types ────────────────────────────────────────────────────────────────────

type StepState = "active" | "completed" | "inactive"

// ─── Root Context ─────────────────────────────────────────────────────────────

interface StepperContextValue {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
  steps: string[]
  registerStep: (value: string) => () => void
}

const StepperContext = React.createContext<StepperContextValue>({
  value: "",
  onValueChange: () => {},
  orientation: "horizontal",
  steps: [],
  registerStep: () => () => {},
})

// ─── Item Context ─────────────────────────────────────────────────────────────

interface StepperItemContextValue {
  value: string
  state: StepState
  index: number
  disabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue>({
  value: "",
  state: "inactive",
  index: -1,
  disabled: false,
})

// ─── Stepper ──────────────────────────────────────────────────────────────────

function Stepper({
  value: controlledValue,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [internalValue, setInternalValue] = React.useState(defaultValue ?? "")
  const [steps, setSteps] = React.useState<string[]>([])

  const activeValue = controlledValue !== undefined ? controlledValue : internalValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (controlledValue === undefined) setInternalValue(newValue)
      onValueChange?.(newValue)
    },
    [controlledValue, onValueChange]
  )

  const registerStep = React.useCallback((stepValue: string) => {
    setSteps((prev) => {
      if (prev.includes(stepValue)) return prev
      return [...prev, stepValue]
    })
    return () => {
      setSteps((prev) => prev.filter((v) => v !== stepValue))
    }
  }, [])

  return (
    <StepperContext.Provider
      value={{
        value: activeValue,
        onValueChange: handleValueChange,
        orientation,
        steps,
        registerStep,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          orientation === "horizontal" ? "flex-row items-center" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

function StepperItem({
  value,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
  disabled?: boolean
}) {
  const {
    value: activeValue,
    orientation,
    steps,
    registerStep,
  } = React.useContext(StepperContext)

  React.useLayoutEffect(() => {
    return registerStep(value)
  }, [value, registerStep])

  const activeIndex = steps.indexOf(activeValue)
  const itemIndex = steps.indexOf(value)

  const state: StepState =
    value === activeValue
      ? "active"
      : itemIndex >= 0 && activeIndex >= 0 && itemIndex < activeIndex
        ? "completed"
        : "inactive"

  return (
    <StepperItemContext.Provider
      value={{ value, state, index: itemIndex, disabled }}
    >
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-row items-center flex-1"
            : "flex-col",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = React.useContext(StepperContext)
  const { value, state, index, disabled } = React.useContext(StepperItemContext)

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      role="tab"
      aria-selected={state === "active"}
      disabled={disabled}
      onClick={() => onValueChange(value)}
      className={cn(
        "inline-flex shrink-0 items-center gap-2.5 rounded-md text-left outline-none transition-all",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      <span
        data-slot="stepper-indicator"
        data-state={state}
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
          state === "active" &&
            "border-primary bg-primary text-primary-foreground",
          state === "completed" &&
            "border-primary bg-primary text-primary-foreground",
          state === "inactive" &&
            "border-input bg-background text-muted-foreground"
        )}
      >
        {state === "completed" ? (
          <CheckIcon className="size-4" />
        ) : index >= 0 ? (
          index + 1
        ) : null}
      </span>
      {children}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = React.useContext(StepperItemContext)

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-semibold leading-none transition-colors",
        state === "inactive" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = React.useContext(StepperItemContext)

  return (
    <p
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-xs text-muted-foreground transition-colors",
        state === "active" && "text-foreground/70",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = React.useContext(StepperContext)
  const { state } = React.useContext(StepperItemContext)

  return (
    <div
      data-slot="stepper-separator"
      data-state={state}
      data-orientation={orientation}
      aria-hidden="true"
      className={cn(
        "rounded-full bg-muted transition-colors data-[state=completed]:bg-primary",
        orientation === "horizontal"
          ? "mx-2 h-0.5 flex-1"
          : "ml-4 w-px min-h-8",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

function StepperContent({ className, ...props }: React.ComponentProps<"div">) {
  const { state } = React.useContext(StepperItemContext)

  return (
    <div
      data-slot="stepper-content"
      data-state={state}
      className={cn(state !== "active" && "hidden", className)}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

