          : "ml-4 w-px min-h-8",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

function StepperContent({ className, ...props }: React.ComponentProps<"div">) {
  const { state } = React.useContext(StepperItemContext)

  return (
    <div
      data-slot="stepper-content"
      data-state={state}
      className={cn(state !== "active" && "hidden", className)}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

